import React, { useEffect, useState } from 'react';
import { Pie, Bar, Line } from 'react-chartjs-2';
import axios from 'axios';
import './Reports.css';

import {
  Chart as ChartJS,
  ArcElement,
  BarElement,
  LineElement,
  PointElement,
  CategoryScale,
  LinearScale,
  Title,
  Tooltip,
  Legend,
} from 'chart.js';

ChartJS.register(
  ArcElement,
  BarElement,
  LineElement,
  PointElement,
  CategoryScale,
  LinearScale,
  Title,
  Tooltip,
  Legend
);

function Reports() {
  const [chartData, setChartData] = useState(null);
  const [predictions, setPredictions] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const analyticsRes = await axios.get('http://localhost:5000/api/ml/analytics');
        const predictionRes = await axios.get('http://localhost:5000/api/ml/ml-demand-prediction');

        setChartData(analyticsRes.data);
        setPredictions(predictionRes.data);
      } catch (error) {
        console.error('Error fetching data:', error);
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, []);

  if (loading) {
    return <div className="reports-container"><p>Loading analytics...</p></div>;
  }

  if (!chartData) {
    return <div className="reports-container"><p>No data available</p></div>;
  }

  // Prepare next month prediction data
  const nextMonthPrediction = predictions?.results?.slice(0, 5).reduce((sum, item) => sum + item.predicted, 0) || 0;
  const currentMonthActual = predictions?.results?.slice(0, 5).reduce((sum, item) => sum + item.actual, 0) || 0;
  const growthRate = currentMonthActual > 0 ? (((nextMonthPrediction - currentMonthActual) / currentMonthActual) * 100).toFixed(2) : 0;

  return (
    <div className="reports-container">
      <h1>📊 Analytics & ML Predictions</h1>

      {/* ML Predictions Section */}
      <div className="prediction-section">
        <h2>🤖 Next Month Predictions (Linear Regression)</h2>
        <div className="prediction-cards">
          <div className="prediction-card">
            <h3>Current Month Sales</h3>
            <p className="prediction-value">₹{Math.round(currentMonthActual * 83)}</p>
          </div>
          <div className="prediction-card">
            <h3>Predicted Next Month</h3>
            <p className="prediction-value">₹{Math.round(nextMonthPrediction * 83)}</p>
          </div>
          <div className="prediction-card">
            <h3>Growth Rate</h3>
            <p className={`prediction-value ${growthRate >= 0 ? 'positive' : 'negative'}`}>
              {growthRate >= 0 ? '📈' : '📉'} {growthRate}%
            </p>
          </div>
          <div className="prediction-card">
            <h3>Model Accuracy</h3>
            <p className="prediction-value">{(predictions?.accuracy * 100).toFixed(1)}%</p>
          </div>
        </div>
      </div>

      {/* Charts Section */}
      <div className="chart-section">
        <h2>📊 Category Distribution</h2>
        {chartData.pie && chartData.pie.labels ? (
          <Pie data={chartData.pie} />
        ) : (
          <p>No category data available</p>
        )}
      </div>

      <div className="chart-section">
        <h2>💰 Average Price by Category</h2>
        {chartData.bar && chartData.bar.labels ? (
          <Bar data={chartData.bar} />
        ) : (
          <p>No price data available</p>
        )}
      </div>

      <div className="chart-section">
        <h2>📈 Monthly Sales Trend</h2>
        {chartData.line && chartData.line.labels ? (
          <Line data={chartData.line} />
        ) : (
          <p>No sales trend data available</p>
        )}
      </div>

      {/* Top Predictions */}
      {predictions?.results && (
        <div className="predictions-table">
          <h2>🎯 Top Product Demand Predictions</h2>
          <table>
            <thead>
              <tr>
                <th>Product</th>
                <th>Actual Sales</th>
                <th>Predicted Sales</th>
                <th>Variance</th>
              </tr>
            </thead>
            <tbody>
              {predictions.results.slice(0, 10).map((item, idx) => {
                const variance = ((item.predicted - item.actual) / item.actual * 100).toFixed(1);
                return (
                  <tr key={idx}>
                    <td>{item.name}</td>
                    <td>{Math.round(item.actual)}</td>
                    <td>{Math.round(item.predicted)}</td>
                    <td className={variance >= 0 ? 'positive' : 'negative'}>{variance}%</td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}

export default Reports;
